**파일: `api/src/main/kotlin/com/maum/backend/graphql/follow/FollowResolver.kt`**

```kotlin
// After - 커서 기반 페이지네이션 적용
@QueryMapping
fun followingList(
    @AuthenticationPrincipal userId: String,
    @Argument first: Int = 20,
    @Argument after: String? = null,  // 커서 (마지막 followId)
): FollowConnection {
    val pageable = PageRequest.of(0, first, Sort.by("createdAt").descending())
    val result = followService.getFollowingList(userId, pageable)

    return FollowConnection(
        edges = result.content.map { projection ->
            FollowEdge(
                cursor = projection.followId,
                node = FollowUserDto(
                    userId = projection.userId,
                    nickname = projection.nickname,
                    profileImageUrl = projection.profileImageUrl,
                )
            )
        },
        pageInfo = PageInfo(
            hasNextPage = result.hasNext(),
            endCursor = result.content.lastOrNull()?.followId,
        )
    )
}
